#!/usr/bin/env python3
"""Append remaining 5 topics to facts_world_history.py"""

def write_topic(f, topic_num, topic_ru, topic_kz, facts):
    f.write(f'    # {"=" * 63}\n')
    f.write(f'    # {topic_num}. {topic_ru} / {topic_kz}  ({len(facts)} facts)\n')
    f.write(f'    # {"=" * 63}\n')
    for item in facts:
        level, pru, pkz, oru, okz, corr, eru, ekz = item
        f.write("    (\n")
        f.write(f'        "{level}",\n')
        f.write(f'        "{topic_ru}", "{topic_kz}",\n')
        f.write(f'        "{pru}",\n')
        f.write(f'        "{pkz}",\n')
        f.write(f'        {oru},\n')
        f.write(f'        {okz},\n')
        f.write(f'        {corr},\n')
        f.write(f'        "{eru}",\n')
        f.write(f'        "{ekz}"\n')
        f.write("    ),\n")

